import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import StormShieldMap from '../components/StormShieldMap';
import { getSheltersApi, getActiveAlertsApi } from '../api/apiServices';
import './CitizenDashboard.css';

const Dashboard = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [user, setUser] = useState(null);

  const [shelters, setShelters] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [selectedShelter, setSelectedShelter] = useState(null);
  const [userLoc, setUserLoc] = useState({ lat: 10.8231, lng: 106.6297 });

  const fallbackAlerts = [
    { id: 1, type: 'Ngập lụt', severity: 'HIGH', distance: '2km' },
    { id: 2, type: 'Cây đổ', severity: 'MEDIUM', distance: '500m' }
  ];

  const fallbackShelters = [
    { id: 1, name: 'Trường THPT A', capacity: 50, distance: '1.2km' },
    { id: 2, name: 'Nhà văn hóa B', capacity: 100, distance: '3.0km' }
  ];

  const fallbackActivities = [
    { id: 1, type: 'Yêu cầu cứu trợ: Y tế', status: 'Đang xử lý', statusType: 'warning', icon: 'medical_services' },
    { id: 2, type: 'Yêu cầu cứu trợ: Di dời', status: 'Hoàn tất', statusType: 'success', icon: 'directions_walk' }
  ];

  useEffect(() => {
    // Check authentication
    const token = localStorage.getItem('token');
    const storedUser = localStorage.getItem('user');

    if (!token || !storedUser) {
      navigate('/login');
      return;
    }

    try {
      const parsedUser = JSON.parse(storedUser);
      setUser(parsedUser);
    } catch (e) {
      localStorage.clear();
      navigate('/login');
    }
  }, [navigate]);

  useEffect(() => {
    const fetchMapData = () => {
      getSheltersApi()
        .then((res) => setShelters(res.data || []))
        .catch(console.error);

      getActiveAlertsApi()
        .then((res) => setAlerts(res.data || []))
        .catch(console.error);
    };

    fetchMapData();

    const interval = setInterval(() => {
      fetchMapData();
    }, 120000);

    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) =>
          setUserLoc({
            lat: pos.coords.latitude,
            lng: pos.coords.longitude
          }),
        (err) => console.warn('Dashboard Geo fallback:', err)
      );
    }

    return () => clearInterval(interval);
  }, []);

  const nearestShelters = useMemo(() => {
    const calculateDistance = (lat1, lon1, lat2, lon2) => {
      const R = 6371;
      const dLat = ((lat2 - lat1) * Math.PI) / 180;
      const dLon = ((lon2 - lon1) * Math.PI) / 180;
      const a =
        Math.sin(dLat / 2) * Math.sin(dLat / 2) +
        Math.cos((lat1 * Math.PI) / 180) *
          Math.cos((lat2 * Math.PI) / 180) *
          Math.sin(dLon / 2) *
          Math.sin(dLon / 2);
      const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
      return R * c;
    };

    const available = shelters.filter(
      (s) => s.status === 'AVAILABLE' && s.latitude != null && s.longitude != null
    );

    const withDistance = available.map((s) => ({
      ...s,
      distance: calculateDistance(userLoc.lat, userLoc.lng, s.latitude, s.longitude)
    }));

    return withDistance.sort((a, b) => a.distance - b.distance).slice(0, 3);
  }, [shelters, userLoc]);

  const nearestAlerts = useMemo(() => {
    return alerts.slice(0, 3);
  }, [alerts]);

  const handleLogout = () => {
    localStorage.clear();
    navigate('/login');
  };

  if (!user) return null;

  return (
    <div className="cd-dashboard-wrapper">
      {/* SideNavBar */}
      <nav className="cd-sidebar">
        <div className="cd-sidebar-header">
          <span className="material-symbols-outlined icon-fill" style={{ color: 'white', fontSize: '1.875rem' }}>shield</span>
          <div>
            <h1 className="cd-sidebar-title">StormShield</h1>
            <p className="cd-sidebar-subtitle">Hệ thống cứu hộ công dân</p>
          </div>
        </div>
        <div className="cd-sidebar-menu">
          <Link to="/dashboard" className="cd-menu-item active">
            <span className="material-symbols-outlined icon-fill">home</span>
            <span className="cd-menu-text">Trang chủ</span>
          </Link>
          <Link to="/alerts" className="cd-menu-item">
            <span className="material-symbols-outlined">warning</span>
            <span className="cd-menu-text">Cảnh báo</span>
          </Link>
          <Link to="/shelters" className="cd-menu-item">
            <span className="material-symbols-outlined">roofing</span>
            <span className="cd-menu-text">Nơi trú ẩn</span>
          </Link>
          <Link to="/request-list" className="cd-menu-item">
            <span className="material-symbols-outlined">assignment</span>
            <span className="cd-menu-text">Yêu cầu của tôi</span>
          </Link>
          <Link to="/reports" className="cd-menu-item">
            <span className="material-symbols-outlined">analytics</span>
            <span className="cd-menu-text">Báo cáo của tôi</span>
          </Link>
          <Link to="/notifications" className="cd-menu-item">
            <span className="material-symbols-outlined">notifications</span>
            <span className="cd-menu-text">Thông báo</span>
          </Link>
        </div>
      </nav>

      {/* Main Content Canvas */}
      <main className="cd-main-content">
        {/* TopNavBar (Mobile mainly) */}
        <header className="cd-mobile-header">
          <div className="cd-mobile-brand">
            <span className="material-symbols-outlined icon-fill" style={{ color: 'var(--color-primary-container)', fontSize: '1.5rem' }}>shield</span>
            <span className="cd-mobile-brand-title">StormShield</span>
          </div>
          <div className="cd-mobile-actions">
            <button className="cd-notification-btn" style={{ position: 'relative' }} onClick={() => navigate('/notifications')}>
              <span className="material-symbols-outlined">notifications</span>
              <span className="cd-notification-badge" style={{ width: '8px', height: '8px', top: '4px', right: '4px' }}></span>
            </button>
            <img 
              alt="Citizen Avatar" 
              className="cd-avatar" 
              src="https://lh3.googleusercontent.com/aida-public/AB6AXuDuc4cCt3wWTRFypkY2af59gS06nfCtQCAkdQkdH_vEwVsMikFySQrZm8RXlw7wAA9E83autkW1wesgJPX2cpyq2ymjniN7Pgq8L-RtJY_HbE62F4FeNJgZw54QpP2vzlUrFLlVp-9IDPm5P6bzv1KyLqTzfv6RPVVg4GVfHq9Kt4ziCofNIgvQFrL13R10Df22I-IcJ1_1n09gGAhyOhJi7zPXrn6wlVk3LWzftPsM2ILCU_8m43vFj7gUWejQT4ZYayA9lPv9HRU" 
            />
            <button onClick={handleLogout} className="cd-logout-btn" title="Đăng xuất" style={{ padding: '4px' }}>
              <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>logout</span>
            </button>
          </div>
        </header>

        {/* Desktop Header / User Context */}
        <div className="cd-desktop-header">
          <div>
            <h2 className="cd-header-title">Tổng quan</h2>
          </div>
          <div className="cd-header-actions">
            <div style={{ position: 'relative' }}>
              <button className="cd-notification-btn" onClick={() => navigate('/notifications')}>
                <span className="material-symbols-outlined">notifications</span>
                <span className="cd-notification-badge">3</span>
              </button>
            </div>
            <div className="cd-user-profile">
              <div className="cd-user-info">
                <p className="cd-user-name">{user.fullName || 'Nguyễn Văn A'}</p>
                <p className="cd-user-role">Công dân</p>
              </div>
              <img 
                alt="Avatar" 
                className="cd-avatar-lg" 
                src="https://lh3.googleusercontent.com/aida-public/AB6AXuAsH6k8dJkT6t3bUexK9hfTrlSrwhGgwnhbR2mqHQ6TEAsDNOg05GNwsD9zCuIR7aL2aqVEv3C2gHyeG9piv15DifuttuC7xoUFZ5V30P0cVX7v_-jXgr_4OrVYUWiqBUPGRgrT-EYQ9EF8oox070LopdMzv6gPxH1NtKPuG6rQ4Vvm7KZuB0EB0JbdVXMvzAUie7Z3FD7qZwNZiqnBMMggUKGykPaDbVl62lhzfnuxppDmSvop9ePylAXUE9YuiQvxkwwmA2YimMs" 
              />
              <button onClick={handleLogout} className="cd-logout-btn" title="Đăng xuất" style={{ marginLeft: '8px' }}>
                <span className="material-symbols-outlined">logout</span>
              </button>
            </div>
          </div>
        </div>

        <div className="cd-content">
          {/* Hero / Status Section */}
          <section className="cd-hero-section">
            <div className="cd-hero-left">
              <div className="cd-hero-title-row">
                <h1 className="cd-hero-title">Xin chào, bạn đang ở khu vực an toàn</h1>
                <span className="cd-status-badge">
                  <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>check_circle</span>
                  An toàn
                </span>
              </div>
              <p className="cd-hero-desc">Theo dõi cảnh báo, tìm nơi trú ẩn và gửi yêu cầu cứu trợ khi cần thiết.</p>
            </div>
            <div className="cd-hero-right">
              <div className="cd-location-badge">
                <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>location_on</span>
                Quận 1, TP.HCM
              </div>
            </div>
          </section>

          {/* Quick Action Grid */}
          <section className="cd-quick-actions">
            <Link to="/request-support" className="cd-action-btn cd-action-danger">
              <div className="cd-action-icon-wrapper">
                <span className="material-symbols-outlined icon-fill" style={{ fontSize: '24px' }}>sos</span>
              </div>
              <span className="cd-action-text">Gửi yêu cầu cứu trợ</span>
            </Link>
            <Link to="/report-alert" className="cd-action-btn cd-action-warning">
              <div className="cd-action-icon-wrapper">
                <span className="material-symbols-outlined icon-fill" style={{ fontSize: '24px' }}>report_problem</span>
              </div>
              <span className="cd-action-text">Báo cáo sự cố</span>
            </Link>
            <Link to="/shelters" className="cd-action-btn cd-action-success">
              <div className="cd-action-icon-wrapper">
                <span className="material-symbols-outlined icon-fill" style={{ fontSize: '24px' }}>roofing</span>
              </div>
              <span className="cd-action-text">Tìm shelter gần nhất</span>
            </Link>
            <Link to="/map" className="cd-action-btn cd-action-primary">
              <div className="cd-action-icon-wrapper">
                <span className="material-symbols-outlined icon-fill" style={{ fontSize: '24px' }}>route</span>
              </div>
              <span className="cd-action-text">Xem đường đi an toàn</span>
            </Link>
          </section>

          {/* Main Layout Grid */}
          <div className="cd-grid-layout">
            {/* Left Column: Map & Summary */}
            <div className="cd-left-column">
              {/* Interactive Map Card */}
              <div className="cd-card cd-map-card">
                <div className="cd-card-header cd-map-header">
                  <h3 className="cd-card-title">Bản đồ khu vực</h3>
                  <div className="cd-map-controls">
                    <div className="cd-search-input-wrapper">
                      <span className="material-symbols-outlined">search</span>
                      <input className="cd-search-input" placeholder="Tìm kiếm địa điểm..." type="text" />
                    </div>
                    <select className="cd-filter-select">
                      <option>Tất cả</option>
                      <option>Cảnh báo</option>
                      <option>Shelter</option>
                    </select>
                  </div>
                </div>
                <div className="cd-map-area">
                  <div style={{ height: '100%', width: '100%', display: 'flex', flexDirection: 'column' }} className="map-container-inner">
                    <StormShieldMap
                      shelters={shelters}
                      alerts={alerts}
                      selectedShelter={selectedShelter}
                      initialRoutingDestination={location.state?.routeToDest}
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Right Column: Contextual Data */}
            <div className="cd-right-column">
              {/* Alerts Near You */}
              <div className="cd-card">
                <div className="cd-card-header">
                  <h3 className="cd-card-title">Cảnh báo trong bán kính 20km</h3>
                </div>
                <div className="cd-card-content">
                  {nearestAlerts.length > 0 ? (
                    nearestAlerts.map(alert => (
                      <Link to={`/alerts/${alert.id}`} className="cd-list-item" key={alert.id}>
                        <div className={`cd-list-item-icon ${alert.severity === 'HIGH' ? 'error' : 'warning'}`}>
                          <span className="material-symbols-outlined icon-fill">
                            {alert.type === 'FLOOD' ? 'water_drop' : 'warning'}
                          </span>
                        </div>
                        <div className="cd-list-item-content">
                          <div className="cd-list-item-header">
                            <p className="cd-list-item-title">{alert.type}</p>
                            <span className={`cd-list-item-badge ${alert.severity === 'HIGH' ? 'error' : 'warning'}`}>
                              {alert.severity}
                            </span>
                          </div>
                          <p className="cd-list-item-desc">
                            <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>location_on</span>
                            {alert.locationName || 'Khu vực gần bạn'}
                          </p>
                        </div>
                      </Link>
                    ))
                  ) : (
                    fallbackAlerts.map(alert => (
                      <Link to={`/alerts/${alert.id}`} className="cd-list-item" key={alert.id}>
                        <div className={`cd-list-item-icon ${alert.severity === 'HIGH' ? 'error' : 'warning'}`}>
                          <span className="material-symbols-outlined icon-fill">water_drop</span>
                        </div>
                        <div className="cd-list-item-content">
                          <div className="cd-list-item-header">
                            <p className="cd-list-item-title">{alert.type}</p>
                            <span className={`cd-list-item-badge ${alert.severity === 'HIGH' ? 'error' : 'warning'}`}>
                              {alert.severity === 'HIGH' ? 'Nguy hiểm cao' : 'Trung bình'}
                            </span>
                          </div>
                          <p className="cd-list-item-desc">
                            <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>distance</span>
                            Cách đây {alert.distance}
                          </p>
                        </div>
                      </Link>
                    ))
                  )}
                </div>
              </div>

              {/* Shelters Near You */}
              <div className="cd-card">
                <div className="cd-card-header">
                  <h3 className="cd-card-title">Nơi trú ẩn gần nhất</h3>
                </div>
                <div className="cd-card-content">
                  {nearestShelters.length > 0 ? (
                    nearestShelters.map((s, idx) => (
                      <div key={s.id}>
                        <Link to={`/shelters/${s.id}`} className="cd-list-item" onClick={() => setSelectedShelter(s)}>
                          <div className="cd-list-item-icon success">
                            <span className="material-symbols-outlined">school</span>
                          </div>
                          <div className="cd-list-item-content">
                            <p className="cd-list-item-title" style={{ marginBottom: '0.25rem' }}>{s.name}</p>
                            <div className="cd-list-item-header" style={{ marginBottom: 0 }}>
                              <span className="cd-list-item-desc">
                                <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>distance</span>
                                {s.distance.toFixed(1)} km
                              </span>
                              <span className="cd-list-item-desc-right">
                                {s.capacity > 0 ? `Còn ${s.capacity} chỗ` : 'Hết chỗ'}
                              </span>
                            </div>
                          </div>
                        </Link>
                        {idx < nearestShelters.length - 1 && <div className="cd-divider"></div>}
                      </div>
                    ))
                  ) : (
                    fallbackShelters.map((s, idx) => (
                      <div key={s.id}>
                        <Link to={`/shelters/${s.id}`} className="cd-list-item">
                          <div className="cd-list-item-icon success">
                            <span className="material-symbols-outlined">school</span>
                          </div>
                          <div className="cd-list-item-content">
                            <p className="cd-list-item-title" style={{ marginBottom: '0.25rem' }}>{s.name}</p>
                            <div className="cd-list-item-header" style={{ marginBottom: 0 }}>
                              <span className="cd-list-item-desc">
                                <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>distance</span>
                                {s.distance}
                              </span>
                              <span className="cd-list-item-desc-right">Còn {s.capacity} chỗ</span>
                            </div>
                          </div>
                        </Link>
                        {idx < fallbackShelters.length - 1 && <div className="cd-divider"></div>}
                      </div>
                    ))
                  )}
                </div>
              </div>

              {/* Recent Requests & Notifications */}
              <div className="cd-card">
                <div className="cd-card-header">
                  <h3 className="cd-card-title">Cập nhật hoạt động</h3>
                </div>
                <div className="cd-activity-list">
                  {fallbackActivities.map(act => (
                    <div className="cd-activity-item" key={act.id}>
                      <div className="cd-activity-header">
                        <div className="cd-activity-title-group">
                          <span className="material-symbols-outlined cd-activity-icon">{act.icon}</span>
                          <span className="cd-activity-title">{act.type}</span>
                        </div>
                        <span className={`cd-activity-status ${act.statusType}`}>{act.status}</span>
                      </div>
                    </div>
                  ))}
                  <div className="cd-activity-item highlight">
                    <div className="cd-notification-item">
                      <div className="cd-notification-dot active"></div>
                      <div>
                        <p className="cd-notification-text">Cảnh báo ngập lụt mới tại Quận 1</p>
                        <p className="cd-notification-time">Vừa xong</p>
                      </div>
                    </div>
                  </div>
                  <div className="cd-activity-item">
                    <div className="cd-notification-item">
                      <div className="cd-notification-dot inactive"></div>
                      <div>
                        <p className="cd-notification-text">Yêu cầu cứu trợ #123 đã được tiếp nhận</p>
                        <p className="cd-notification-time">2 giờ trước</p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
